#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=5e3+5,MAXM=2e5+5;
string str=" ",s,c;
int n,trie[MAXN][35],ne[MAXN],idx;
int q[MAXN],cnt[MAXN],len[MAXN];
bool f[MAXM];
void insert(string s)
{
	int p=0;
	FOR(i,0,s.size()-1)
	{
		int v=s[i]-'A';
		if(!trie[p][v])trie[p][v]=++idx;
		p=trie[p][v];
	}
	++cnt[p],len[p]=s.size();
}
void build()
{
	int h=0,t=-1;
	FOR(i,0,25)
	{
		if(trie[0][i])q[++t]=trie[0][i];
	}
	wh(h<=t)
	{
		int tt=q[h++];
		FOR(i,0,25)
		{
			int &p=trie[tt][i];
			if(!p)
			{
				p=trie[ne[tt]][i];
			}
			else
			{
				ne[p]=trie[ne[tt]][i];
				q[++t]=p;
			}
		}
	}
}
signed main(void)
{
	wh(cin>>c,c!=".")
	{
		insert(c);
	}
	build();
	wh(cin>>s)
	{
		str+=s;
	}
	f[0]=true;
	int pro=0;
	FOR(i,1,str.size()-1)
	{
		int v=str[i]-'A';
		pro=trie[pro][v];
		int p=pro;
		wh(p)
		{
			if(f[i-len[p]])
			{
				f[i]=true;
				break;
			}
			p=ne[p];
		}
	}
	ROF(i,str.size()-1,1)
	{
		if(f[i])
		{
			write(i);
			exit(false);
		}
	}
    pc('0');
	return false;
}
